export const ADHelpMap: Record<string, string> = {
  "run": "Usage: belz ad run <PUBLISHED_ID> [PAYLOAD] [flags]\n\nExecute a published Automation Designer method.\n\nArguments:\n  <PUBLISHED_ID>      The unique ID of the published method version.\n  [PAYLOAD]           JSON string or path to a JSON file. Defaults to '{}' if omitted.\n\nFlags:\n  --raw               Include raw payload in output.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad run 40ba5566efa95b033ef7af8f7f30ee09\n  belz ad run 40ba5566efa95b033ef7af8f7f30ee09 '{\"type\":\"LT262A\"}'\n  belz ad run 40ba5566efa95b033ef7af8f7f30ee09 ./data/payload.json --raw --llm",
  "test": "Usage: belz ad test <UUID> [flags]\n\nExecute a draft Automation Designer method for testing and inspection.\n\nArguments:\n  <UUID>              The UUID of the draft method to test.\n\nFlags:\n  --inputs <FILE>     Path to a JSON file of input values. Prompts interactively if omitted.\n  --verbose           Show detailed execution trace for each step.\n  --force             Bypass cache and fetch a fresh method definition.\n  --raw               Include raw execution payload in output.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad test 1234-5678\n  belz ad test 1234-5678 --verbose\n  belz ad test 1234-5678 --inputs ./test-data.json\n  belz ad test 1234-5678 --inputs ./test-data.json --raw --llm",
  "run-suites": "Usage: belz ad run-suites [flags]\n\nExecute all saved regression test suites found in the 'suites/' directory.\nEach suite is verified for HTTP 200 and a non-failed execution result.\n\nFlags:\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad run-suites\n  belz ad run-suites --env nsm-qa\n  belz ad run-suites --llm",
  "category": "belz ad category create <name> [flags]\n\nCreate a new AD category (service). Only the create sub-action is supported\ntoday.\n\nFlags:\n  --description <d>   Human-readable description\n  --private           Use accessMode=PRIVATE (default is PUBLIC)\n  --yes               Skip the interactive confirmation prompt\n  --llm               Emit a JSON envelope; --yes is required in this mode\n\nDefault permissions are ALLOW_ALL_INTERNAL_USERS; edit in the UI afterwards\nif a stricter ACL is needed.",
  "export-category": "belz ad export-category <category-id> [flags]\n\nExport an entire category (all methods) via\n/rest/api/automation/chain/export/category/{id}.\n\nFlags:\n  --out <file>    Write the exported JSON to a file instead of stdout\n  --llm           Emit a JSON envelope",
  "save-suite": "Usage: belz ad save-suite <UUID> --name <NAME> [flags]\n\nCapture and save a regression test suite for a method.\nStores input values for repeated use with 'belz ad run-suites'.\n\nArguments:\n  <UUID>              The UUID of the method to save a test suite for.\n\nFlags:\n  --name <NAME>       Name for this test suite, e.g. 'smoke-test-login'. (required)\n  --inputs <FILE>     Path to a JSON file of input values. Prompts interactively if omitted.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad save-suite 123e4567-e89b-12d3-a456-426614174000 --name smoke-test-login\n  belz ad save-suite 123e4567-e89b-12d3-a456-426614174000 --name smoke-test-login --inputs ./inputs.json",
  "trace": "Usage: belz ad trace <UUID> [flags]\n\nLocate an AD method on every environment relative to its dev version history.\n\nThe dev (spine) environment's version history is treated as a totally-ordered\n\"spine\" of content states. Every environment is then placed as a pointer into\nthat spine: its latest-published version is fingerprinted and matched to a\nspine entry. This shows which change of a method has reached which env — the\ninput to release collision and leak detection.\n\nFingerprints are structural and parser-agnostic: they hash the method's\n(orderIndex, kind, description) step tuples plus the input contract, so a V1\nlive response and a V2 history response of the same logic match.\n\nAD chain UUIDs are stable across environments, so one UUID resolves everywhere.\n\nArguments:\n  <UUID>                AD chain UUID.\n\nFlags:\n  --spine <env>         Environment whose history is the spine. Default: nsm-dev.\n  --help, -h            Show this help message.\n\nGlobal Flags:\n  --llm                 Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad trace 4bbac4b95962448669dcaf518567e752\n  belz ad trace 4bbac4b95962448669dcaf518567e752 --spine nsm-dev --llm\n\nStatus values per environment:\n  latest               env content matches the newest spine entry\n  behind               env content matches an older spine entry\n  ahead-or-diverged    env content matches no spine entry\n  missing              method has no published version on that env\n  error                env could not be queried (auth/network)",
  "fetch": "Usage: belz ad fetch <UUID|URL> [flags]\n\nFetch an Automation Designer method by UUID or URL, cache it, and hydrate all service definitions.\n\nArguments:\n  <UUID|URL>          The UUID of the method, or a full AD URL\n                      (e.g. https://nsm-dev.nc.verifi.dev/automation-designer/Category/426f97...).\n\nFlags:\n  --raw               Include raw method payload in output.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad fetch 426f97096b0221bb830d954c45ac9f84\n  belz ad fetch https://nsm-dev.nc.verifi.dev/automation-designer/NSM.Staff/426f97096b0221bb830d954c45ac9f84\n  belz ad fetch 426f97096b0221bb830d954c45ac9f84 --raw --env nsm-qa --llm",
  "publish": "belz ad publish <uuid> [flags]\n\nPublish a draft — promotes the current draft contents to the published\nversion of the same method. Returns the published UUID and a version-sync\nsummary.\n\nFlags:\n  --yes    Skip the interactive confirmation prompt\n  --llm    Emit a JSON envelope; --yes is required in this mode\n\nSafety:\n  - Always routes through resolveDraftTarget: if you pass a PUBLISHED UUID\n    belz automatically switches to the linked draft before publishing.\n  - Re-fetches both draft and published after the publish call and reports\n    whether they are in sync.",
  "import": "belz ad import <file> [flags]\n\nImport one or more method definitions via\n/rest/api/automation/chain/import. The file contents are posted verbatim;\nbelz only extracts method names for the confirmation prompt.\n\nPrerequisites (from the AD API docs):\n  1. Dependent methods must already exist in the target environment.\n  2. Category / service names must match.\n  3. Database account names must match.\n  4. Helper method configurations must exist.\n\nFlags:\n  --yes    Skip the interactive confirmation prompt\n  --llm    Emit a JSON envelope; --yes is required in this mode",
  "services": "belz ad services [flags]\n\nList all services from /rest/api/automation/services (the core service catalog\nused to build step identifiers). Both internal and external services are\nincluded by default.\n\nFlags:\n  --internal          Only show services with internalService=true\n  --search <q>        Case-insensitive substring match on name / label / alias\n  --llm               Emit a JSON envelope with {total, services[]}\n\nExample:\n  belz ad services --search redis\n  belz ad services --internal --llm",
  "find": "Usage: belz ad find [LIST|PICK|QUERY] [flags]\n\nFind Automation Designer methods and categories from a cached local index.\nWith no query (or `LIST`), lists all categories with method counts.\n\nArguments:\n  [LIST|PICK|QUERY]   LIST shows category counts.\n                      PICK opens an interactive fzf picker.\n                      QUERY runs ranked search over methods and categories.\n\nFlags:\n  --refresh           Rebuild method index from API before searching.\n  --limit <N>         Maximum number of matches to return. (default: 20)\n  --open              Open selected method URL in browser. (pick mode only)\n  --raw               Include raw cached index data in output.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad find list\n  belz ad find pick _lookupDCIN --open\n  belz ad find \"documents helper\" --limit 30\n  belz ad find _lookupDCIN --refresh --llm",
  "save": "belz ad save <file> --uuid <draftUuid> [--yes]\n\nSave an edited method definition to an existing draft. Goes through\nresolveDraftTarget — if you pass a PUBLISHED UUID, belz automatically switches\nto the linked draft and tells you it did so.\n\nThe <file> is a JSON overlay with any of these optional keys:\n  name, summary, description, buttonLabel, internalMethod\n  inputs[]  — objects with {code, testValue} update testValue on matching inputs\n  parsedSteps[] — objects with {orderIndex} plus any of:\n    source      — CUSTOM_CODE step: full decoded JS/Python source (plain text)\n    sql         — SQL step: full decoded SQL body (plain text, NOT base64)\n    expression  — SPEL_ECHO step: the SpEL expression string\n    description — any step: updated description\n\n  Agents should always pass plain text — the serializer handles base64\n  re-encoding automatically.\n\nFlags:\n  --uuid <id>      Target DRAFT UUID (or PUBLISHED; we switch to its draft)\n  --category <n>   (future) Category name for --new\n  --new            Create a new method in the given --category (not yet wired)\n  --yes            Skip the interactive confirmation prompt\n  --llm            Emit a JSON envelope; --yes is required in this mode\n\nSafety:\n  - Never saves to a PUBLISHED method. Writes always target the linked draft.\n  - Re-fetches the saved method after the write so automationId-dependent\n    tests work immediately.\n  - Refuses to emit a payload where a CUSTOM_CODE step with >1 outputs is\n    missing `elementToRetrieve` on any output.",
  "sql": "Usage: belz ad sql <subcommand> [args] [flags]\n\nRun SQL queries via Automation Designer database services.\n\nSubcommands:\n  dbs                 List available database auth configurations.\n  run <QUERY>         Execute a SQL read (SELECT) query.\n  update <QUERY>      Execute a SQL write (UPDATE/DELETE) query.\n  insert <QUERY>      Execute a SQL INSERT query.\n  modify <QUERY>      Execute a DDL schema change (ALTER TABLE, CREATE INDEX, etc.).\n  tui                 Start an interactive SQL session.\n\nFlags (dbs):\n  --raw               Include raw API response.\n\nFlags (run):\n  --db <NAME|ID>      Database nickname or ID.\n                      Default resolution: BELZ_SQL_DEFAULT_DB → NSM_Read_DB\n  --raw               Include raw operation metadata and execution response.\n\nFlags (update):\n  --db <NAME|ID>      Database nickname or ID.\n  --raw               Include raw operation metadata and execution response.\n\nFlags (insert):\n  --db <NAME|ID>      Database nickname or ID.\n  --raw               Include raw operation metadata and execution response.\n\nFlags (modify):\n  --db <NAME|ID>      Database nickname or ID.\n  --raw               Include raw operation metadata and execution response.\n\nFlags (tui):\n  --db <NAME|ID>      Pre-select database (skips interactive DB prompt).\n  --mode <MODE>       Pre-select mode: read | insert | update | modify (skips interactive mode prompt).\n  --format <MODE>     Row output format: table (default) | json.\n  --timing            Print timing details after each statement.\n  --page-size <N>     Rows per page for pagination. (default: 50)\n  --no-history        Disable persisted query history for this session.\n\nTUI meta commands:\n  \\q  \\h  \\status  \\db  \\use <db>  \\mode [read|insert|update|modify]  \\history  \\clear  \\timing  \\format [table|json]  \\last  \\r\n\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      use `belz envs` to list all available envs.\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad sql dbs\n  belz ad sql run \"select * from users limit 1\"\n  belz ad sql run \"select * from users limit 1\" --db NSM_QA_DB\n  belz ad sql update \"UPDATE users SET status = 'active' WHERE id = 1\" --db NSM_Write_DB\n  belz ad sql update \"DELETE FROM logs WHERE created_at < '2024-01-01'\" --db NSM_Write_DB\n  belz ad sql insert \"INSERT INTO users (name) VALUES ('test')\" --db NSM_Write_DB\n  belz ad sql modify \"ALTER TABLE users ADD COLUMN age INT\" --db NSM_Write_DB\n  belz ad sql modify \"CREATE INDEX IF NOT EXISTS idx_name ON users(name)\" --db NSM_Write_DB\n  belz ad sql tui\n  belz ad sql tui --db NSM_QA_DB --format json --timing\n  belz ad sql tui --mode insert --db NSM_Write_DB\n  BELZ_SQL_DEFAULT_DB=NSM_QA_DB belz ad sql run \"select now()\"",
  "outputs": "belz ad outputs <uuid> [flags]\n\nPrint a method's input/variable/output contract without any step internals.\n\nFlags:\n  --v2     Parse the method via the V2 API (falls back to V1 if unsupported)\n  --llm    Emit a JSON envelope with {inputs[], variables[], outputs[]}\n\nExample:\n  belz ad outputs 4a1b2c3d... --llm | jq '.data.inputs'",
  "test-cases": "belz ad test-cases <uuid> [flags]\n\nList the persistent test cases attached to a method's test suite.\n\nFlags:\n  --llm    Emit a JSON envelope with {testSuiteId, testCases[], total}\n\nExample:\n  belz ad test-cases 4a1b2c3d...",
  "categories": "belz ad categories [flags]\n\nList all AD categories (services) — both user-generated and system-generated.\n\nFlags:\n  --user     Only show USER_GENERATED categories\n  --system   Only show SYSTEM_GENERATED categories\n  --llm      Emit a JSON envelope with {total, filter, categories[]}\n\nExample:\n  belz ad categories --user\n  belz ad categories --llm | jq '.data.categories[] | select(.type == \"SYSTEM_GENERATED\")'",
  "export": "belz ad export <method-id-or-uuid> [flags]\n\nExport a single method via /rest/api/automation/chain/export/{id}.\n\nFlags:\n  --out <file>    Write the exported JSON to a file instead of stdout\n  --llm           Emit a JSON envelope with {id, writtenTo, bytes, preview}\n\nExample:\n  belz ad export 98765 --out /tmp/method.json",
  "child-info": "belz ad child-info <category> <method-name> [flags]\n\nFetch metadata for a method referenced by name from another method's step\n(e.g. when a step calls \"Helpers.Legacy.echo\" you can look up the child's\ninputs/outputs without already knowing its UUID).\n\nBacks GET /rest/api/automation-systems/{category}/automation-apis/{method-name}.\n\nFlags:\n  --llm    Emit a JSON envelope\n\nExample:\n  belz ad child-info Helpers.Legacy echo",
  "show": "Usage: belz ad show <UUID> [flags]\n\nDisplay the structure and metadata of an Automation Designer method.\nThe method definition is fetched and cached automatically. Cached data older\nthan 5 minutes is served instantly while a background process refreshes it\n(stale-while-revalidate); use --force to fetch fresh synchronously.\n\nArguments:\n  <UUID|URL>              The UUID of the method, or a full AD URL\n                          (e.g. https://nsm-dev.nc.verifi.dev/automation-designer/Category/426f97...).\n\nFlags:\n  --inputs                Show a table of input arguments.\n  --services              Show a list of service steps.\n  --service-detail <N>    Show detailed info for the Nth service step.\n  --full                  Include expanded per-service logic details.\n  --force                 Bypass cache and fetch a fresh method definition.\n  --raw                   Include raw payloads in output.\n  --open, -o              Open the editable draft URL in your default browser\n                          (uses the draft uuid even when the input is the\n                          published id).\n  --help, -h              Show this help message.\n\nGlobal Flags:\n  --env <name>            Set active environment. (default: nsm-dev)\n                          Available: nsm-dev | nsm-qa | nsm-uat\n  --llm                   Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz ad show 1234-5678 --inputs\n  belz ad show 1234-5678 --services\n  belz ad show 1234-5678 --service-detail 2\n  belz ad show 1234-5678 --service-detail 2 --raw --llm\n  belz ad show 1234-5678 --force\n  belz ad show 1234-5678 --open\n  belz ad show 1234-5678 -o",
  "test-case": "belz ad test-case <action> [args]\n\nManage persistent test cases attached to an AD method's test suite.\n\nActions:\n  list <uuid>                             List test cases (alias of belz ad test-cases)\n  create <uuid> --file <tc.json> [--yes]  Create one test case from a file\n  update <uuid> <testCaseId> --file <f>   Update a test case (V1 supports this)\n  delete <testCaseId> [--yes]             Delete a test case\n  bulk <uuid> --file <cases.json> [--yes] Bulk create an array of test cases\n  run-suite <uuid> [--yes]                Execute the method's test suite (async)\n  delete-suite <testSuiteId> [--yes]      Delete a test suite\n\nCommon flags:\n  --yes    Skip the interactive confirmation prompt\n  --llm    Emit a JSON envelope; --yes is required in this mode\n\nTest case schema (see ad-rest-api-crud-and-testing.md §\"Test Case Payload\nStructure\" for the authoritative form):\n  {\n    \"name\": \"test.operation.description\",\n    \"description\": \"...\",\n    \"active\": true,\n    \"inputs\": [\n      {\n        \"fieldCode\": \"userId\",\n        \"value\": \"{\\\"value\\\": \\\"42\\\", \\\"properties\\\": [{\\\"value\\\": []}]}\"\n      }\n    ],\n    \"assertions\": []\n  }\n\nGotcha: /testsuite/execute does NOT evaluate assertions. executionStatus=PASS\nmeans the method ran without errors, not that assertions passed. Use\n`belz ad test-report` for full evaluation results.",
  "history": "belz ad history <action> <uuid> [flags]\n\nBrowse and restore previous versions of an AD method. Calls the published\nExpertly.Automation.Method.History service methods via the execute endpoint.\n\nActions:\n  list <uuid>                         List all saved versions\n  show <uuid> --version N             Fetch + parse a specific version (shows\n                                      step kinds, inputs, full structure)\n  diff <uuid> --from N --to M           Compare two versions side by side (step\n                                      count, kind changes, input changes)\n  restore <uuid> --version N [--yes]  Revert the method to a previous version\n\nFlags:\n  --version <N>    Version number (for show/restore)\n  --from <N>       First version (for diff)\n  --to <M>         Second version (for diff)\n  --yes            Skip interactive confirmation (required for --llm mode)\n  --llm            Emit a JSON envelope\n\nNotes:\n  - 'list' returns metadata only (no full body). Use 'show' to fetch the\n    full jsonDefinition at a specific version.\n  - 'diff' fetches both versions in parallel and compares step structure,\n    step bodies, and inputs. It does NOT compute a textual diff of the\n    jsonDefinition — it compares parsed step representations.\n  - 'restore' is a write operation and goes through the confirmation gate.\n    It calls the Expertly.Automation.Method.History.restore internal service.\n  - Version numbers are integers starting at 1. Use 'list' to see which\n    versions exist.\n\nExamples:\n  belz ad history list 4e3f3f8d5f8a8160e879ae012989f6f9\n  belz ad history show 4e3f3f8d... --version 3\n  belz ad history diff 4e3f3f8d... --from 1 --to 5\n  belz ad history show 4e3f3f8d... --version 1 --llm | jq '.data.method.parsedSteps'\n  belz ad history restore 4e3f3f8d... --version 3 --yes",
  "test-report": "belz ad test-report [flags]\n\nPrint the latest test-suite execution report from\n/rest/api/automation/chain/testsuite/report.\n\nFlags:\n  --llm    Emit a JSON envelope",
  "show-code": "belz ad show-code <uuid> [flags]\n\nDump decoded custom-code step source from an AD method.\n\nFlags:\n  --step <N>     Only dump the step at orderIndex N (default: all CUSTOM_CODE steps)\n  --out <file>   Write the source to a file instead of stdout\n  --v2           Parse the method via the V2 API (falls back to V1 if unsupported)\n  --llm          Emit a JSON envelope with {uuid, snippets[], sourceVersion}\n\nExamples:\n  belz ad show-code 4a1b2c3d...\n  belz ad show-code 4a1b2c3d... --step 2\n  belz ad show-code 4a1b2c3d... --out /tmp/code.js\n  belz ad show-code 4a1b2c3d... --llm | jq '.data.snippets[0].source'",
  "state": "belz ad state <uuid> [flags]\n\nPrint draft/published linkage, versions, and publish-staleness for a method.\n\nFlags:\n  --v2     Parse the method via the V2 API (falls back to V1 if unsupported)\n  --llm    Emit a JSON envelope with {draftUuid, publishedUuid, state, versions}\n\nNotes:\n  - Wraps lib/draft-guard.ts:resolveDraftTarget() and is the safe read-only\n    way to inspect draft/published state before calling any write command.\n  - Exit code is 0 even when the method is PUBLISHED without a linked draft;\n    the envelope `ok` field surfaces the distinction.\n\nExample:\n  belz ad state 4a1b2c3d... --llm | jq '.data'",
};

export const PDHelpMap: Record<string, string> = {
  "analyze": "Usage: belz pd analyze [PAGE_ID] [flags]\n\nRecursively analyze a page, collecting all nested components and AD method references.\nUses the default page list from config when PAGE_ID is omitted.\n\nArguments:\n  [PAGE_ID]           UUID of the page to analyze. Uses default pages if omitted.\n\nFlags:\n  --compliance        Verify discovered AD IDs against master_ids.txt.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz pd analyze\n  belz pd analyze 49fa2576...\n  belz pd analyze 49fa2576... --compliance\n  belz pd analyze --compliance --llm",
  "validate": "Usage: belz pd validate <INPUT> [flags]\n\nValidate a Page Designer page or component against common error patterns.\nChecks for orphan bindings, unused variables, invalid components, and more.\n\nArguments:\n  <INPUT>             One of:\n                      • App page URL:  https://<domain>/pages/<path>\n                      • PD page URL:   https://.../ui-designer/page/<id>\n                      • PD symbol URL: https://.../ui-designer/symbol/<name>\n                      • Bare hex ID:   48b75e11e166e6b19e5796d59a936228\n                      • Component name: n_s_staff_email_correspondence\n\nValidation Checks:\n  ORPHAN_BINDING          {%var%} used but variable not defined (error)\n  UNUSED_VARIABLE         Variable defined but never referenced (warn)\n  FORM_FIELD_PROPS        exp-form-field with props instead of field (error)\n  CHILDREN_NOT_ARRAY      children is object instead of array (error)\n  TABLE_NO_DATASOURCE     exp-data-table missing datasourceState (warn)\n  INVALID_SLIDE_TOGGLE    mat-slide-toggle used (no runtime declaration) (error)\n  INVALID_EXPANSION_HEADER  mat-expansion-panel-header used (error)\n  MISSING_ONINIT_VAR      HTTP trigger onInit but no onInit variable (warn)\n  EMPTY_EVENT_META        eventMeta: {} on variable-triggered call (warn)\n  DYNAMIC_COLS_INITIAL    exp-data-table with [columns] + initialValue (warn)\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n  --help, -h          Show this help message.\n\nExamples:\n  belz pd validate 48b75e11e166e6b19e5796d59a936228\n  belz pd validate n_s_staff_email_correspondence\n  belz pd validate https://nsm-dev.nc.verifi.dev/ui-designer/page/48b75e11e166e6b19e5796d59a936228\n  belz pd validate 48b75e11e166e6b19e5796d59a936228 --llm",
  "lock": "Usage: belz pd lock <action> [pageId]\n\nManage PD edit locks. Writes always go through an acquire/release cycle via\n`belz pd save` automatically — this command exists for cases where you need\nto hold the lock across multiple manual operations.\n\nActions:\n  acquire <pageId>    PUT /pages/lock/<pageId> with body {pageLockAction:\"ACQUIRED\"}.\n                      Returns 409 if another editor holds the lock.\n  release <pageId>    PUT /pages/lock/<pageId>?pageLockAction=RELEASED.\n                      Idempotent — safe to call even if no lock is held.\n  status              List locks currently held by belz in this env. (Local\n                      record, kept at ~/.belz/pd-locks/<env>.json.)\n\nExamples:\n  belz pd lock acquire 4f126300499e4d83cd07a35b4d9af9e7\n  belz pd lock release 4f126300499e4d83cd07a35b4d9af9e7\n  belz pd lock status\n\nNotes:\n  • Body-on-acquire vs query-on-release is a server quirk — do not normalize.\n  • The PD editor auto-acquires on page open. If acquire returns 409, close\n    the editor or have the current holder release first.",
  "publish": "Usage: belz pd publish <pageId> [--landing] [--host <id> ...] [--yes]\n\nPublish a PD draft page to its deployable sibling. Wraps POST\n/pages/<draftId>/publish in an acquire/release lock cycle.\n\nArguments:\n  <pageId>            PD draft page id. If a PUBLISHED id is given, belz\n                      resolves the linked draft and publishes that (with a\n                      warning). --force overrides the guard.\n\nFlags:\n  --landing           Mark this as the site's landing page (maps to\n                      body.landingPage:true).\n  --host <id>         Publish to a specific deployment host. Repeatable —\n                      `--host a --host b` sends body.hostIds:\"a,b\".\n  --yes, -y           Required to perform the publish.\n  --force             Bypass the PUBLISHED-input draft-guard refusal.\n  --help, -h          Show this help message.\n\nExamples:\n  belz pd publish 4f126300499e4d83cd07a35b4d9af9e7 --yes\n  belz pd publish 4f126300499e4d83cd07a35b4d9af9e7 --landing --yes\n  belz pd publish <id> --host 1 --host 2 --yes --llm",
  "find-ad-methods": "Usage: belz pd find-ad-methods <ID> [flags]\n\nList all Automation Designer method IDs referenced in a page or component.\n\nArguments:\n  <ID>                UUID of the page, or name of the component.\n\nFlags:\n  --component         Treat <ID> as a component name instead of a page UUID.\n  --recursive, -r     Deep-scan all child components recursively.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz pd find-ad-methods 49fa2576...\n  belz pd find-ad-methods n_s_staff_email_correspondence --component\n  belz pd find-ad-methods 49fa2576... --recursive --llm",
  "find": "Usage: belz pd find [query] [flags]\n       belz pd find list [--components]\n       belz pd find pick [query] [flags]\n\nSearch for pages and components in the Page Designer.\nThe index is cached locally for 7 days; use --refresh to rebuild.\n\nArguments:\n  [query]             Search term (name, route, or ID). Omit to browse.\n\nSubcommands:\n  list                List all pages (add --components for components).\n  pick                Interactive fuzzy picker (requires fzf).\n\nFlags:\n  --type page|component  Restrict results to one entity type.\n  --refresh           Rebuild the index from the API.\n  --limit <N>         Max results to show (default: 20, max: 200).\n  --open              Open selected item in browser (pick mode only).\n  --llm               Output structured JSON envelope.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n\nExamples:\n  belz pd find notice\n  belz pd find notice --type page\n  belz pd find list\n  belz pd find list --components\n  belz pd find pick\n  belz pd find pick LT-260 --open\n  belz pd find --refresh",
  "save": "Usage: belz pd save <pageId> (--overlay <file> | --config <file>) [flags]\n\nSafe-edit entry point. Applies a validated edit to a PD page.\n\nExactly one of --overlay / --config must be provided.\n\n  --overlay <file>    Targeted JSON overlay (see shape below). Preferred.\n  --config <file>     Raw full inner-configuration JSON (escape hatch).\n\nFlow:\n  1. Resolve draft target (refuses PUBLISHED unless --force).\n  2. Fetch + parse current page → HydratedPage \"before\".\n  3. Apply edit → HydratedPage \"after\".\n  4. Validator gate: errors abort unless --force; warnings print + proceed.\n  5. Acquire lock, PUT (partial or full), release lock.\n  6. Re-fetch, report old/new versionId.\n\nFlags:\n  --overlay <file>    See OVERLAY SHAPE below.\n  --config <file>     File is a parsed inner-configuration object. belz\n                      stringifies it and sends with partialUpdate=false.\n  --dry-run           Run the full flow but skip the network PUT.\n  --force             Bypass validator ERRORS (warnings still print).\n                      Also overrides draft-guard PUBLISHED refusal.\n  --yes, -y           Required to perform any real write.\n  --help, -h          Show this help message.\n\nOVERLAY SHAPE:\n  {\n    \"variables\": {\n      \"add\":    [{\"name\":\"x\",\"type\":\"String\",\"initialValue\":\"\"}],\n      \"update\": [{\"name\":\"x\",\"initialValue\":\"changed\"}],\n      \"remove\": [\"old\"]\n    },\n    \"derived\": {\n      \"add\":    [{\"name\":\"d\",\"from\":[\"x\"],\"spec\":\"(function(p){return p.x})\"}],\n      \"update\": [{\"name\":\"d\",\"spec\":\"...\"}],\n      \"remove\": [\"dead\"]\n    },\n    \"httpRequests\": {\n      \"update\": [{\"callId\":\"sc-001\",\"request\":{\"body\":\"{}\"}}],\n      \"remove\": [\"sc-dead\"]\n    },\n    \"elements\": {\n      \"operations\": [\n        {\"key\":\"layout.children[0].props.innerHTML\",\"value\":\"New\",\n         \"operation\":\"UPDATE\",\"dataType\":\"STRING\"}\n      ]\n    },\n    \"styles\": {\"replace\":\".latest-version .x { color: red }\"}\n  }\n\nSTRATEGY:\n  Partial save is used when the overlay only has:\n    variables.update, httpRequests.update, elements.operations, styles.replace\n  Full save is used when the overlay touches:\n    variables.add/remove, derived.*, httpRequests.add/remove\n\nExamples:\n  belz pd save 4f126300499e4d83cd07a35b4d9af9e7 --overlay ./ed.json --dry-run\n  belz pd save 4f126300499e4d83cd07a35b4d9af9e7 --overlay ./ed.json --yes\n  belz pd save 4f126300499e4d83cd07a35b4d9af9e7 --config ./full.json --yes\n  belz pd save <id> --overlay ./ed.json --force --yes --llm | jq '.data.validation.issues'",
  "show": "Usage: belz pd show <INPUT> [flags]\n\nDisplay the structure and metadata of a Page Designer page or component.\nThe config is fetched and cached automatically. Cached data older than 5\nminutes is served instantly while a background process refreshes it\n(stale-while-revalidate); use --force to fetch fresh synchronously.\n\nArguments:\n  <INPUT>             One of:\n                      • App page URL:  https://<domain>/pages/<path>\n                      • PD page URL:   https://.../ui-designer/page/<id>\n                      • PD symbol URL: https://.../ui-designer/symbol/<name>\n                      • Bare hex ID:   48b75e11e166e6b19e5796d59a936228\n                        (auto-detects page vs. component)\n                      • Component name: n_s_staff_email_correspondence\n\nFlags:\n  --vars              Show all variables (user-defined + derived).\n  --http              Show all HTTP service calls.\n  --components        Show the legacy (flat-name) layout tree.\n  --tree              Show the full layout tree with node-kind badges\n                      ([FORM] [TABLE] [BTN] [SYM] [LAYOUT] [-]). Highlights\n                      known pitfalls inline (USES-PROPS!, DYN-CLASS!, NO-DS).\n  --node <id>         Dump kind-specific detail for a single node by id\n                      (field vs props, bindings, validations, event wires).\n  --var-graph         Show the per-variable write/read/derive/trigger map.\n                      Flags \"dead\" variables (no writers AND no readers).\n  --var-detail <name> Show full config for a specific variable or derived.\n  --http-detail <N>   Show full config for the Nth HTTP call (1-indexed).\n  --full              Include all sections + all details.\n  --recursive, -r     Include recursive dependency tree and all AD method IDs.\n                      Requires components.json in the current directory.\n  --force             Bypass cache and fetch fresh config.\n  --raw               Include raw configuration string and source API fields.\n  --open, -o          Open the editable draft URL in your default browser\n                      (uses the draft id for pages, the component name for\n                      symbols).\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz pd show 48b75e11e166e6b19e5796d59a936228\n  belz pd show https://nsm-dev.nc.verifi.dev/ui-designer/page/48b75e11e166e6b19e5796d59a936228\n  belz pd show n_s_staff_email_correspondence\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --vars\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --http\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --components\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --var-detail showLoader\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --http-detail 1\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --full\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --force --llm\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --tree\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --node __node_id_submit_btn\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --var-graph\n  belz pd show 48b75e11e166e6b19e5796d59a936228 --open\n  belz pd show AHS_DMV_Profile_Detail -o",
  "history": "Usage: belz pd history <action> <pageId> [flags]\n\nBrowse and restore previous versions of a PD page. Backed by the server-\nside history service at /rest/api/pagedesigner/pages/history.\n\nActions:\n  list <pageId>                        List every saved version of the page.\n  show <pageId> --version <vid>        Parse + validate one historical version.\n  diff <pageId> --from A --to B        Structural diff between two versions\n                                       (variables, derived, http, node adds/\n                                       removes/kind-changes, styles flag).\n  restore <pageId> --version <vid>     Revert the page to that version. Wraps\n                                       the PUT in an acquire/release lock.\n                                       Requires --yes.\n\nFlags:\n  --version <vid>    Version id (for show / restore).\n  --from <A>         First version id (for diff).\n  --to <B>           Second version id (for diff).\n  --limit <N>        Cap \"list\" rows (default 50).\n  --yes              Skip interactive confirmation (required for restore).\n  --force            (reserved for future --force variants)\n  --help, -h         Show this help message.\n\nNotes:\n  • list returns metadata only — use show for full config.\n  • diff compares structure, not line-by-line JSON.\n  • A brand-new page shows an empty list until its first save.\n  • Draft and published variants of the same page have SEPARATE histories\n    (each is a distinct pageId on the server).\n\nExamples:\n  belz pd history list 4f126300499e4d83cd07a35b4d9af9e7\n  belz pd history show 4f126300499e4d83cd07a35b4d9af9e7 --version 406403\n  belz pd history diff 4f126300499e4d83cd07a35b4d9af9e7 --from 406403 --to 406410\n  belz pd history restore 4f126300499e4d83cd07a35b4d9af9e7 --version 406403 --yes\n  belz pd history list 4f126300499e4d83cd07a35b4d9af9e7 --limit 10 --llm | jq '.data.versions'",
  "preflight": "Usage: belz pd preflight <pageId> [--overlay <file>]\n\nRead-only dry-run. Fetches the current page, optionally applies an overlay,\nruns the validator, and reports what would change. Makes NO network writes.\n\nArguments:\n  <pageId>            PD page or component id (hex UUID).\n\nFlags:\n  --overlay <file>    Apply a JSON overlay before validation. See `belz pd\n                      save` help for the overlay shape.\n  --help, -h          Show this help message.\n\nExit code:\n  0 if the post-overlay page validates cleanly.\n  1 if any validator ERROR fires.\n\nExamples:\n  belz pd preflight 4f126300499e4d83cd07a35b4d9af9e7\n  belz pd preflight 4f126300499e4d83cd07a35b4d9af9e7 --overlay ./edits.json\n  belz pd preflight 4f126300499e4d83cd07a35b4d9af9e7 --overlay ./edits.json --llm \\\n    | jq '.data.validation.issues'",
};

export const TWHelpMap: Record<string, string> = {
  "comments": "Usage: belz tw comments <TASK_ID|URL> [flags]\n\nFetch all comments for a Teamwork task, ordered chronologically.\n\nArguments:\n  <TASK_ID|URL>         Numeric task ID or full Teamwork task URL.\n\nFlags:\n  --help, -h            Show this help message.\n\nGlobal Flags:\n  --llm                 Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz tw comments 26917411\n  belz tw comments https://projects.webintensive.com/app/tasks/26917411\n  belz tw comments 26917411 --llm",
  "task": "Usage: belz tw task <TASK_ID|URL> [flags]\n\nFetch a Teamwork task by ID or URL, including assignees, tags, status,\nworkflow stage, description, comment stats, and subtasks.\n\nArguments:\n  <TASK_ID|URL>         Numeric task ID or full Teamwork task URL.\n\nFlags:\n  --help, -h            Show this help message.\n\nGlobal Flags:\n  --llm                 Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz tw task 26917411\n  belz tw task https://projects.webintensive.com/app/tasks/26917411\n  belz tw task 26917411 --llm",
  "items": "Usage: belz tw items <TASK_ID|URL> [flags]\n\nScan a Teamwork ticket — its description, all comments, and every subtask's\ncomments — for the AD chains, PD pages/symbols, and SQL changes it delivers.\nThis is the \"linker\" stage of a release audit: it turns free-text dev notes\ninto a structured item set.\n\nIt recognizes the three conventions documented in the release-prep skill:\n  A. URLs        — automation-designer/<cat>/<id>, ui-designer/page/<id>,\n                   ui-designer/symbol/<name>\n  B. Labeled CSV — \"PD Pages Published : <hex>,<hex>\"\n  C. Labeled CSV — \"AD (Published Id): <hex>,<hex>\"\n\nSQL is split into DB (DDL: ALTER/CREATE/DROP TABLE/INDEX) and Corrective fixes\n(DML: INSERT/UPDATE/DELETE).\n\nThe \"recommended\" set is drawn from the LATEST dev-note block — long tickets\noften contain superseded ID lists from rewritten approaches. Every reference\nis also listed with full provenance so the recommendation can be audited.\n\nArguments:\n  <TASK_ID|URL>         Numeric task ID or full Teamwork task URL.\n\nFlags:\n  --help, -h            Show this help message.\n\nGlobal Flags:\n  --llm                 Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz tw items 26917411\n  belz tw items https://projects.webintensive.com/app/tasks/26917411\n  belz tw items 26917411 --llm\n\nNotes:\n  - PD page URLs yield DRAFT ids; resolve to published deployables with\n    'belz pd show' before adding to release-items.txt.\n  - SQL extraction is heuristic — always verify the captured statements.",
};

export const TopHelpMap: Record<string, string> = {
  "envs": "Usage: belz envs [flags]\n\nList all configured environments and show which one is active.\nUse --env <name> to switch environments for any command.\n\nFlags:\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz envs\n  belz envs --env nsm-qa\n  belz ad get <UUID> --env nsm-qa",
  "migrate-legacy": "Usage: belz migrate <subcommand> [flags]\n\nRun NSM migrations through the DB migration tool workflow.\n\nSubcommands:\n  profiles            Discover available NSM migration profiles.\n  run                 Start and monitor a migration run.\n\nFlags (profiles):\n  --refresh           Bypass cache and force live profile discovery.\n  --raw               Include discovery diagnostics in output.\n\nFlags (run):\n  --module <MODULE>   Module to migrate. (required)\n                      Known: AD_Method | PD | RD | CUSTOM_PD | AD_COMPARISON_REPORT |\n                             PD_COMPARISON_REPORT | PD_MIGRATION_STATUS | AD_MIGRATION_STATUS\n                      Use --module-custom for any other value.\n  --ids <CSV>         Comma- or space-separated UUID list. (required)\n  --profile <VALUE>   Explicit NSM profile (e.g. devncdns_qancdns).\n\n  --source-env <ENV>  Source environment alias for profile derivation.\n  --target-env <ENV>  Target environment alias for profile derivation.\n                      Aliases: nsm-dev | nsm-qa | nsm-uat | nsm-stage | nsm-stage2\n\n  --ids-file <PATH>   Read UUIDs from a file (newline/comma/space separated).\n  --crud <Y|N>        Use CRUD API. (default: Y)\n  --async <Y|N>       Async migration. (default: Y)\n  --migrate-dependents <Y|N>  Migrate dependents. (default: N)\n\n  Note: Always use --crud Y, --async Y, --migrate-dependents N (the defaults) unless\n  explicitly instructed otherwise.\n\n  --script-name <TEXT>  Override script name.\n  --migration-id <UUID>  Optional migration ID field value.\n  --cleanup <auto|never>  Cleanup after stream closes. (default: auto)\n  --out <PATH>        Artifact output path (directory or .json file).\n  --raw               Include raw start response and stream events.\n  --quiet             Suppress step-by-step progress output.\n\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Set active environment. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz migrate profiles\n  belz migrate profiles --refresh --raw\n  belz migrate run --module PD --ids 4a5384efb22322c1af9bbbe62b2b8be4 --profile devncdns_qancdns\n  belz migrate run --module AD_Method --ids-file ./ids.txt --source-env nsm-dev --target-env nsm-qa\n  belz migrate run --module AD_Method --ids-file ./ids.txt --source-env nsm-dev --target-env nsm-qa --out ./runs --llm",
  "config": "Usage: belz config <subcommand> [flags]\n\nManage belz credentials and environment configuration.\n\nSubcommands:\n  get             Show URL, user, password status, and cached token for the active env.\n  token           Print the raw Bearer token to stdout (for scripting/clipboard).\n  edit            Interactively add, edit, or remove credentials in ~/.belz/config.json.\n\nFlags:\n  --help, -h      Show this help message.\n\nGlobal Flags:\n  --env <name>    Set active environment. (default: nsm-dev)\n                  Available: nsm-dev | nsm-qa | nsm-uat\n  --llm           Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz config get\n  belz config get --env nsm-qa\n  belz config token\n  belz config token --env nsm-qa --llm\n  belz config edit",
  "web": "belz web [subcommand] [flags]\n\nManage the Belzabar web app (Next.js, port 65535).\n\nSubcommands:\n  start     Start the web app in the background (default)\n  stop      Stop the running web app\n  restart   Restart the web app\n  status    Show whether the web app is running and its PID\n\nFlags:\n  -v, --verbose   Stream logs to the terminal instead of running in background.\n                  Only applies to 'start'. Process runs in foreground (blocking).\n\nExamples:\n  belz web                  Start the web app in the background\n  belz web -v               Start and stream logs to the terminal (foreground)\n  belz web start            Explicit start (same as 'belz web')\n  belz web stop             Stop the running web app\n  belz web restart          Restart the web app\n  belz web status           Check if the web app is running\n\nThe web app must be built and installed first by running the install script:\n  ./cli/scripts/install.sh\n\nLog file: ~/.belz/logs/web.log\nPID file: ~/.belz/pids/web.pid\nURL:      http://localhost:65535",
  "setup": "Usage: belz setup [flags]\n\nInteractive first-time setup. Walks you through credential entry for each\nbuilt-in environment (nsm-dev, nsm-qa, nsm-uat) and optional Teamwork creds,\nthen writes ~/.belz/config.json.\n\nPasswords are base64-encoded before being stored. The config file is the\nsource of truth: it overrides any matching environment variables.\n\nFlags:\n  --env-file <path>  Load credentials from a .env file instead of prompting.\n                     The file should define NSM_DEV_USER, NSM_DEV_PASSWORD,\n                     NSM_QA_USER, NSM_QA_PASSWORD, NSM_UAT_USER, NSM_UAT_PASSWORD,\n                     TEAMWORK_EMAIL, TEAMWORK_PASSWORD as needed.\n  --force            Overwrite an existing config without asking.\n\nNote: 'belz setup' refuses to run with --llm or on a non-TTY. Use --env-file\nto populate config non-interactively.\n\nExamples:\n  belz setup\n  belz setup --env-file ./secrets.env\n  belz setup --env-file ./secrets.env --force",
  "cache": "Usage: belz cache [flags] [uuid...]\n\nInvalidate server-side cache entries for the active environment via\nPOST /rest/api/cache/invalidate.\n\nPass one or more UUIDs to invalidate specific entries, or omit UUIDs to\ninvalidate the entire cache for the given --type. Wiping the entire cache\nrequires --yes (or interactive confirmation).\n\nArgs:\n  [uuid...]           One or more cache entry UUIDs. Omit to clear all.\n\nFlags:\n  --type <TYPE>       Cache type to invalidate. (default: AUTOMATION)\n  --yes, -y           Skip confirmation when clearing the entire cache.\n  --help, -h          Show this help message.\n\nGlobal Flags:\n  --env <name>        Environment to operate on. (default: nsm-dev)\n                      Available: nsm-dev | nsm-qa | nsm-uat\n  --llm               Output structured JSON envelope for scripting/LLM use.\n  -v, --verbose       Verbose request logging.\n\nExamples:\n  # Invalidate three automation cache entries on the active env\n  belz cache 44014c3707d6b6d8ae848839a1c8d1e7 47425344e088690ff89aa8f1e092c867 4a1d686b87f93b1519f2b61393d4ed7a\n\n  # Same, against nsm-qa\n  belz cache --env nsm-qa <uuid> <uuid>\n\n  # Wipe the entire AUTOMATION cache on nsm-uat (requires confirmation)\n  belz cache --env nsm-uat\n\n  # Wipe everything non-interactively (e.g. from a script or LLM)\n  belz cache --yes --llm\n\n  # Invalidate by a non-default type\n  belz cache --type PAGE <uuid>",
};

export const MigrateHelpMap: Record<string, string> = {
  "run": "belz migrate run  —  Trigger a migration build on Jenkins\n\nUSAGE\n  belz migrate run --profile <profile> --module <type> --ids \"<csv>\" [options]\n  belz migrate run --source-env nsm-qa --target-env nsm-stage --module AD_Method --ids \"<csv>\"\n\nREQUIRED\n  --module <type>              One of: AD_Method, PD, AD_COMPARISON_REPORT,\n                               PD_COMPARISON_REPORT, AD_MIGRATION_STATUS,\n                               PD_MIGRATION_STATUS, AD_Service.\n                               Use --module-custom for arbitrary values.\n\n  --profile <name>             A profile name (e.g. devncdns_qancdns).\n  OR\n  --source-env / --target-env  NCDNS-only: derives the profile (e.g. nsm-qa →\n                               qancdns, nsm-stage → stgncdns).\n\n  --ids \"<csv>\"                Comma-separated UUIDs.\n  OR\n  --ids-file <path>            File containing IDs (comma/space/newline-separated).\n\nOPTIONS\n  --client <name>              Override the client (auto-detected from profile by\n                               default). Names: SEMS, \"Exp AI\", \"YS (YieldSec)\",\n                               \"TH (TownHouse)\", \"NCDNS (NSS)\", DNREC,\n                               \"AHS (NC AHS)\", \"Core/Other\".\n  --migration-id <uuid>        Required for COMPARISON_REPORT / MIGRATION_STATUS.\n  --async Y|N                  Run asynchronously. Default: N.\n  --migrate-dependents Y|N     Migrate dependent methods/pages. Default: N.\n  --devops-tag <ref>           Branch/tag of infra.expertly. Default: develop.\n  --dry-run                    Validate parameters without running migration.\n  --no-auto-approve            Require manual approval in Jenkins (default\n                               sends AUTO_APPROVE=true so we don't get stuck).\n  --no-follow                  Trigger build and return without streaming logs.\n  --out <path>                 Write summary.json + summary.console.log to dir.\n  --quiet                      Suppress progress output.\n  --raw                        Include raw report data in JSON output.\n  --llm                        Emit structured JSON for agent consumption.\n\nCONFIG\n  Reads Jenkins credentials from ~/.belz/config.json:\n    {\n      \"jenkins\": {\n        \"baseUrl\": \"https://jenkins-asg.stg.expertly.cloud\",\n        \"user\": \"<your jenkins user>\",\n        \"password\": \"<base64-encoded password or API token>\",\n        \"migrationJob\": \"expertly.db-migration\"\n      }\n    }\n  Or env vars: BELZ_JENKINS_URL, BELZ_JENKINS_USER, BELZ_JENKINS_PASSWORD.\n\nEXAMPLES\n  # Dry run, NCDNS qa → stage\n  belz migrate run --source-env nsm-qa --target-env nsm-stage \\\\\n    --module AD_Method --ids \"4e74cf38523553112e879308c4a03aef\" --dry-run\n\n  # Real run, explicit profile\n  belz migrate run --profile devncdns_qancdns --module AD_Method \\\\\n    --ids-file ./ids.txt --async Y --out /tmp/m1\n\n  # SEMS qa → stage\n  belz migrate run --profile qasems_stagesems --module AD_Method \\\\\n    --ids \"<uuid>\" --client SEMS",
  "log": "belz migrate logs  —  Print full console output of a Jenkins migration build\n\nUSAGE\n  belz migrate logs <buildNumber> [--llm]\n\nDESCRIPTION\n  Fetches /job/<job>/<n>/consoleText, strips ANSI escapes, and prints it.\n\nEXAMPLES\n  belz migrate logs 743\n  belz migrate logs 743 --llm",
  "profiles": "belz migrate profiles  —  List available Jenkins migration profiles\n\nUSAGE\n  belz migrate profiles [--refresh] [--raw] [--llm]\n\nDESCRIPTION\n  Fetches the PROFILE_NAME parameter choices from the Jenkins\n  `expertly.db-migration` job, groups them by client, and prints them.\n\n  The first invocation hits Jenkins live; subsequent calls read a local cache\n  at ~/.belz/migrations/jenkins-profiles.json. Pass --refresh to force-fetch.\n\nFLAGS\n  --refresh           Bypass the local cache and re-fetch from Jenkins.\n  --raw               Include extra metadata in --llm output.\n  --llm               Emit structured JSON for agent consumption.\n\nEXAMPLES\n  belz migrate profiles\n  belz migrate profiles --refresh\n  belz migrate profiles --llm",
  "status": "belz migrate status  —  Check a Jenkins migration build's status\n\nUSAGE\n  belz migrate status <buildNumber> [--llm]\n\nEXAMPLES\n  belz migrate status 743\n  belz migrate status 743 --llm",
};

export const ReleaseHelpMap: Record<string, string> = {
  "freeze": "Usage: belz release freeze <RELEASE_NAME> [flags]\n\nRecord a production snapshot for a release.\n\nProduction cannot be queried directly, so its state is captured indirectly:\neach item's current STAGE position is frozen into the ledger as the prod\npointer. Run this right after the release is pushed to production.\n\nRequires that `belz release matrix` has already been run for this release\n(it writes the release record this command reads).\n\nArguments:\n  <RELEASE_NAME>        Name of a release previously audited with\n                        `belz release matrix` (the `name` field of its spec).\n\nFlags:\n  --help, -h            Show this help message.\n\nGlobal Flags:\n  --llm                 Output structured JSON envelope for scripting/LLM use.\n\nExamples:\n  belz release freeze may-12-release",
  "matrix": "Usage: belz release matrix <release.json> [flags]\n\nAudit a production release. Given a spec of included and excluded tickets, it\nlinks each ticket to its AD/PD items (via `tw items`), traces every AD item\nacross all environments (via `ad trace`), and reports collisions and leaks.\n\nA COLLISION is an AD method touched by BOTH an included and an excluded\nticket — shipping the included ticket would drag the excluded ticket's edits\nalong. For each collision it reports a LEAK status: whether the excluded\nchange has already reached the stage environment.\n\nThe result is saved to the promotion ledger (~/.belz/promotion/releases/).\n\nrelease.json format:\n  {\n    \"name\": \"may-12-release\",\n    \"included\": [26917411, \"https://.../tasks/26920000\"],\n    \"excluded\": [26918000],\n    \"spineEnv\": \"nsm-dev\",     (optional, default nsm-dev)\n    \"stageEnv\": \"nsm-stage\"    (optional, default nsm-stage)\n  }\n\nArguments:\n  <release.json>        Path to the release spec JSON file.\n\nFlags:\n  --help, -h            Show this help message.\n\nGlobal Flags:\n  --llm                 Output structured JSON envelope for scripting/LLM use.\n\nNotes:\n  - AD-only: PD items are listed per ticket but not yet traced across envs.\n  - Traces run sequentially (the tracer mutates the active env), so a large\n    release can take a few minutes.",
};

export const HELP_FULL_TEXT: string = "NOTE FOR LLM AGENTS: Always use the --llm flag for structured, parseable output.\n  Example: belz ad show <uuid> --llm\n\nbelz — Belzabar CLI\n\nbelz ad <cmd>  —  Automation Designer\n─────────────────────────────────────────────────────────────────────────────\nbelz ad run <published-id>  :->  Execute a published method with empty payload\nbelz ad run <published-id> '<json>'  :->  Execute with an inline JSON payload string\nbelz ad run <published-id> <file.json>  :->  Execute with payload read from a JSON file\nbelz ad run <published-id> '<json>' --raw  :->  Include raw execution payload in output\n\nbelz ad test <uuid>  :->  Execute a draft method; prompts for inputs interactively, returns service outputs and traces\nbelz ad test <uuid> --inputs <file>  :->  Pass a JSON file of input values (skips interactive prompts)\nbelz ad test <uuid> --verbose  :->  Show detailed execution trace for each step\nbelz ad test <uuid> --force  :->  Bypass cache and fetch a fresh method definition before testing\nbelz ad test <uuid> --raw  :->  Include raw execution payload in output\n\nbelz ad run-suites  :->  Run all saved test suites in suites/; verifies HTTP 200 and non-failed execution\nbelz ad run-suites --env nsm-qa  :->  Run all suites against a specific environment\n\n  category create <name>  Create a new AD category (service).\n\n  export-category <id>  Export every method in a category as JSON.\n\nbelz ad save-suite <uuid> --name <name>  :->  Save a named regression test suite (prompts for inputs interactively)\nbelz ad save-suite <uuid> --name <name> --inputs <file>  :->  Save suite using inputs from a JSON file\n\nbelz ad trace <uuid>              :->  Locate an AD method across every environment on the dev spine\nbelz ad trace <uuid> --llm        :->  Output as structured JSON envelope\n\nbelz ad fetch <uuid|url>  :->  Fetch a method by UUID or AD URL; caches and hydrates service definitions\nbelz ad fetch <uuid|url> --raw  :->  Include raw API response alongside the fetch result\nbelz ad fetch <uuid|url> --env nsm-qa  :->  Fetch from a specific environment\n\n  publish <uuid>        Promote a draft to its published version (draft-guarded).\n\n  import <file>         Import method(s) from an exported JSON file.\n\n  services              List platform services (filter with --internal, --search).\n\nbelz ad find  :->  List all service categories with method counts from the local method index\nbelz ad find list  :->  Explicitly list all service categories with method counts\nbelz ad find pick  :->  Open an interactive fzf picker to quickly select a method\nbelz ad find pick <query>  :->  Open fzf picker with an initial query prefilled\nbelz ad find pick <query> --open  :->  Open the selected method URL in browser after picker selection\nbelz ad find <query>  :->  Search methods and categories by name, alias, UUID, and reference ID\nbelz ad find <query> --limit <N>  :->  Return only the top N ranked matches\nbelz ad find <query> --refresh  :->  Rebuild the index from AD APIs before searching\nbelz ad find <query> --raw  :->  Include raw cached index payload in the command output\n\n  save <file> --uuid <id>  Save a JSON overlay onto a draft (draft-guarded).\n\nbelz ad sql dbs  :->  List available SQL database configurations and auth types\nbelz ad sql run \"<query>\"  :->  Execute a SELECT query against the default DB\nbelz ad sql run \"<query>\" --db <name|id>  :->  Execute SELECT against a specific database\nbelz ad sql update \"<query>\" --db <name|id>  :->  Execute UPDATE or DELETE; returns rows affected\nbelz ad sql insert \"<query>\" --db <name|id>  :->  Execute INSERT; returns rows affected and generated IDs/UUIDs\nbelz ad sql modify \"<query>\" --db <name|id>  :->  Execute DDL (ALTER TABLE, CREATE INDEX, etc.)\nbelz ad sql tui  :->  Start an interactive SQL session (prompts for DB and mode: read|insert|update|modify)\nbelz ad sql tui --db <name|id> --mode <read|insert|update|modify>  :->  Start TUI with pre-selected DB and mode\n\n  outputs <uuid>        Print inputs / variables / outputs contract only.\n\n  test-cases <uuid>     List persistent test cases attached to a method.\n\n  categories            List AD categories; filter with --user / --system.\n\n  export <id>           Export a single method as JSON (optionally to a file).\n\n  child-info <cat> <method>  Resolve a child method's inputs/outputs by name.\n\nbelz ad show <uuid|url>  :->  Display structure and metadata of a method (auto-fetched, 5-min cache)\nbelz ad show <uuid|url> --inputs  :->  Show input argument definitions\nbelz ad show <uuid|url> --services  :->  Show service step names and IDs\nbelz ad show <uuid|url> --service-detail <N>  :->  Show detailed info for the Nth service step\nbelz ad show <uuid|url> --full  :->  Show all details including per-service logic and mappings\nbelz ad show <uuid|url> --force  :->  Bypass cache and fetch a fresh method definition\nbelz ad show <uuid|url> --raw  :->  Include raw payloads in output\n\n  test-case <action>    CRUD + suite execution for persistent test cases.\n\n  history <action> <uuid>  Browse and restore previous versions of a method.\n\n  test-report           Latest test-suite execution report.\n\n  show-code <uuid>      Dump decoded custom-code source for all or one CUSTOM_CODE step.\n\n  state <uuid>          Draft/published linkage, version, and staleness check.\n\n\nbelz pd <cmd>  —  Page Designer\n─────────────────────────────────────────────────────────────────────────────\nbelz pd analyze  :->  Recursively analyze all default pages; collect components and AD method references\nbelz pd analyze <page-id>  :->  Recursively analyze a specific page\nbelz pd analyze <page-id> --compliance  :->  Verify discovered AD IDs against master_ids.txt\n\nbelz pd validate <input>  :->  Validate a page/component config against 10 common PD error patterns\nbelz pd validate <input> --llm  :->  Output validation issues as structured JSON envelope\n\n  lock <action>  acquire | release | status — manage PD edit locks.\n\n  publish <pageId>  Publish a PD draft to its deployable sibling.\n\nbelz pd find-ad-methods <page-id>  :->  List all AD method IDs referenced in a page\nbelz pd find-ad-methods <name> --component  :->  List all AD method IDs referenced in a named component\nbelz pd find-ad-methods <page-id> --recursive  :->  Deep-scan all child components and collect every AD method ID\n\nbelz pd find <query>  :->  Search pages and components by name, route, or ID\nbelz pd find list  :->  List all pages (add --components for components)\nbelz pd find pick  :->  Open interactive fzf picker to select a page or component\nbelz pd find pick <query> --open  :->  Open selected item's PD designer URL in browser\nbelz pd find <query> --type page|component  :->  Restrict results to one entity type\nbelz pd find --refresh  :->  Rebuild the 7-day search index from API\n\n  save <pageId>  Apply a validated overlay or full-config to a page.\n\nbelz pd show <input>  :->  Display overview of a page or component (name, IDs, variable/HTTP/component counts)\nbelz pd show <input> --vars  :->  List all user-defined and derived variables with types\nbelz pd show <input> --http  :->  List all HTTP service calls with AD IDs and triggers\nbelz pd show <input> --components  :->  Show the full layout/component tree\nbelz pd show <input> --var-detail <name>  :->  Show full config for a specific variable or derived (spec code, dependencies)\nbelz pd show <input> --http-detail <N>  :->  Show full config for the Nth HTTP call (input bindings, handlers, transform code)\nbelz pd show <input> --full  :->  Show all sections and all details\nbelz pd show <input> --force  :->  Bypass 5-min cache and fetch fresh config\nbelz pd show <input> --raw  :->  Include raw configuration JSON and source API fields\nbelz pd show <input> --recursive  :->  Include recursive component dependency tree and all AD method IDs\n\n  history <action> <pageId>  Browse and restore previous versions of a page.\n\n  preflight <pageId>  Validate (and optionally overlay) a page without saving.\n\n\nbelz tw <cmd>  —  Teamwork\n─────────────────────────────────────────────────────────────────────────────\nbelz tw comments <taskId|url>        :->  Fetch all comments for a Teamwork task\nbelz tw comments <taskId|url> --llm  :->  Output as structured JSON envelope\n\nbelz tw task <taskId|url>        :->  Fetch a Teamwork task with assignees, tags, status, and description\nbelz tw task <taskId|url> --llm  :->  Output as structured JSON envelope\n\nbelz tw items <taskId|url>        :->  Extract AD/PD/SQL release items from a ticket's comments\nbelz tw items <taskId|url> --llm  :->  Output as structured JSON envelope\n\n\nbelz migrate <cmd>  —  Migrations (Jenkins)\n─────────────────────────────────────────────────────────────────────────────\nbelz migrate run                 Trigger a Jenkins migration build, follow its console, and parse the report.\n\nbelz migrate logs <n>            Print the (ANSI-stripped) console output of a Jenkins migration build.\n\nbelz migrate profiles            List Jenkins migration profile choices grouped by client.\n\nbelz migrate status <n>          Show status, result, and parameters of a Jenkins migration build.\n\n\nbelz release <cmd>  —  Release promotion tracking\n─────────────────────────────────────────────────────────────────────────────\nbelz release freeze <name>        :->  Record a prod snapshot from a release's stage state\nbelz release freeze <name> --llm  :->  Output as structured JSON envelope\n\nbelz release matrix <release.json>        :->  Audit a release: link tickets, trace AD items, detect collisions/leaks\nbelz release matrix <release.json> --llm  :->  Output as structured JSON envelope\n\n\nbelz <cmd>  —  Top-level\n─────────────────────────────────────────────────────────────────────────────\nbelz envs  :->  List all configured environments and show which is currently active\nbelz envs --env nsm-qa  :->  Check the auth configuration of a specific environment\n\nbelz migrate profiles  :->  List available NSM migration profiles (source → target environment pairs)\nbelz migrate profiles --refresh  :->  Bypass cache and force live profile discovery\nbelz migrate run --module PD --ids <uuid> --profile <profile>  :->  Migrate a PD page to the next environment\nbelz migrate run --module AD_Method --ids-file <path> --source-env nsm-dev --target-env nsm-qa  :->  Migrate multiple AD methods using a file of IDs\nbelz migrate run --module AD_Method --ids <uuid> --source-env nsm-dev --target-env nsm-qa --out <dir> --llm  :->  Migrate and capture structured output artifacts\n\nbelz config get  :->  Show URL, user, password status, and cached token for the active environment\nbelz config get --env nsm-qa  :->  Show config for a specific environment\nbelz config token  :->  Print the raw Bearer token to stdout (for scripting or clipboard copy)\nbelz config token --env nsm-qa  :->  Print the token for a specific environment\nbelz config edit  :->  Interactively add, edit, or remove credentials in ~/.belz/config.json\n\nbelz web               — Manage the Belzabar web app (Next.js, port 65535)\n  belz web [start]     — Start the web app in the background\n  belz web -v          — Start and stream logs to the terminal (foreground)\n  belz web stop        — Stop the running web app\n  belz web restart     — Restart the web app\n  belz web status      — Check if the web app is running\n\nsetup           Interactive first-time setup: writes ~/.belz/config.json with per-environment credentials.\n\nbelz cache <uuid>...  :->  Invalidate specific cache entries on the active environment\nbelz cache --env nsm-qa  :->  Wipe the entire AUTOMATION cache on a target env (with confirmation)\nbelz cache --type PAGE <uuid>  :->  Invalidate non-AUTOMATION cache entries by UUID\n\nUse 'belz <namespace> <cmd> --help' for full flag documentation and examples.";

export function makeHelpResolver(map: Record<string, string>) {
  return async (cmd: string): Promise<string | null> => map[cmd] ?? null;
}
